import socket
import threading
import json

class Player:
    def __init__(self, position, sightRange):
        self.position = position  # In 2D space for simplicity
        self.sightRange = sightRange

class Game:
    def __init__(self):
        self.players = []

    def add_player(self, player):
        self.players.append(player)

    def get_game_state(self):
        return [player.__dict__ for player in self.players]


class Server:
    def __init__(self, host = 'localhost', port = 55555):
        self.server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        self.server.bind((host, port))
        self.server.listen()
        self.clients = []
        self.game = Game()

    def broadcast(self, message):
        for client in self.clients:
            client.send(message)

    def handle(self, client):
        while True:
            data = client.recv(1024)
            if not data:
                break

            # Assuming data is player's updated position
            data = json.loads(data)
            for player in self.game.players:
                if player.position == data['position']:  # comparing positions to identify player
                    player.position = data['newPosition']

            game_state = self.game.get_game_state()
            self.broadcast(json.dumps(game_state).encode())

        # client disconnected, remove from game
        for i, _client in enumerate(self.clients):
            if _client == client:
                self.clients.pop(i)
                self.game.players.pop(i)

    def run(self):
        while True:
            client, addr = self.server.accept()
            thread = threading.Thread(target=self.handle, args=(client,))
            thread.start()

            # Add new player
            initial_position = (0, 0)
            sight_range = 5
            player = Player(initial_position, sight_range)
            self.game.add_player(player)
            self.clients.append(client)


if __name__ == "__main__":
    server = Server()
    server.run()